  std::string user2_name;
};

std::vector<FriendConnection> analyze_social_network_impl(const std::vector<User>& users, const std::vector<Friendship>& friendships) {
  using namespace sqlgen::literals;

  // Connect to SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Create tables
  sqlgen::create_table<User> | sqlgen::if_not_exists(conn);
  sqlgen::create_table<Friendship> | sqlgen::if_not_exists(conn);

  // Insert data
  sqlgen::insert(users)(conn);
  sqlgen::insert(friendships)(conn);

  // Query 1: Mutual friends using SELF-JOIN
  auto mutual_friends = sqlgen::read<std::vector<FriendConnection>>
    | sqlgen::inner_join<User, "u1">("user_id"_t1 == "user_id1"_t2)
    | sqlgen::inner_join<Friendship, "f1">("user_id"_t1 == "user_id1"_t2)
    | sqlgen::inner_join<Friendship, "f2">("user_id2"_t2 == "user_id1"_t3)
    | sqlgen::inner_join<User, "u2">("user_id2"_t3 == "user_id"_t4)
    | sqlgen::where("user_id"_t1 < "user_id"_t4)
    | sqlgen::group_by("user_id"_t1, "user_id"_t4)
    | sqlgen::having(sqlgen::count("user_id2"_t2) > 0)
    (conn).value();

  // Query 2: Users with more than average friends
  auto avg_friends = sqlgen::read<std::vector<double>>
    | sqlgen::select_from<Friendship, "f">("user_id1"_t1)
    | sqlgen::group_by("user_id1"_t1)
    | sqlgen::to<std::vector<double>>
    (conn).value();

  double average = std::accumulate(avg_friends.begin(), avg_friends.end(), 0.0) / avg_friends.size();

  // Query 3: Friend-of-friend relationships
  auto friend_of_friend = sqlgen::read<std::vector<FriendConnection>>
    | sqlgen::inner_join<User, "u1">("user_id"_t1 == "user_id1"_t2)
    | sqlgen::inner_join<Friendship, "f1">("user_id"_t1 == "user_id1"_t2)
    | sqlgen::inner_join<Friendship, "f2">("user_id2"_t2 == "user_id1"_t3)
    | sqlgen::inner_join<User, "u2">("user_id2"_t3 == "user_id"_t4)
    | sqlgen::where("user_id"_t1 < "user_id"_t4 && 
                  sqlgen::count("user_id2"_t2) == 1)
    (conn).value();

  // Query 4: Most connected users
  auto most_connected = sqlgen::read<std::vector<std::pair<int, int>>>
    | sqlgen::select_from<Friendship, "f">("user_id1"_t1, sqlgen::count("user_id1"_t1))
    | sqlgen::group_by("user_id1"_t1)
    | sqlgen::order_by(sqlgen::count("user_id1"_t1).desc())
    | sqlgen::to<std::vector<std::pair<int, int>>>
    (conn).value();

  // Query 5: Same city recommendations
